nta.declaration:
// Generated from PHY contract IR. Continuous PHY metrics stay outside timed automata.
// Generation mode: with_observers.
// Layout mode: readable.
// Negative scenarios disabled for this generated model.
const int D_meas = 5;
const int D_sig = 5;
const int D_sense = 5;
const int D_report = 5;
const int D_BM = 5;
const int D_child = 5;
const int D_net = 5;
const int T_meas = 5;
const int J_meas = 1;
const int T_report = 5;
const int J_SSB = 1;
const int tau_SSB = 4;

const int SCENARIO_NORMAL = 0;
const int SCENARIO_COMM_DEGRADED = 1;
const int SCENARIO_SENSING_DEGRADED = 2;
const int SCENARIO_JOINT_DEGRADED = 3;
int[0,3] env_scenario = SCENARIO_NORMAL;

clock c_meas, c_sig, c_sense, c_report, c_rec, c_ssb;
clock aos_bs, aos_ctrl, c_env, c_net;
clock c_obs_sense, c_obs_fresh, c_obs_beam;
clock c_obs_channel, c_obs_signal, c_obs_sensing, c_obs_phy;

typedef int[0,4] WaveformT;
const int W_OFDM = 0;
const int W_OTFS = 1;
const int W_AFDM = 2;
const int W_SC = 3;
const int W_OTHER = 4;
WaveformT W = W_OFDM;

chan beam_cmd, controller_report_delivered, extra_ssb_cmd, handover_assist_cmd, mac_report_delivered, measure_tick, new_beam_confirmed, payload_sensing_config, pilot_config, power_cmd, prs_config, recovery_cmd, sensing_mode_cmd, ssb_burst_config, waveform_config;
broadcast chan aos_ctrl_expired, beam_failure, beam_locked, beam_misaligned, beam_report, beam_restored, blockage_detected, channel_degraded, channel_report, contract_violation_bm, contract_violation_ch, contract_violation_ph, contract_violation_sig, contract_violation_sq, degradation_event, handover_hint, mobility_alert, multipath_alert, phy_failure, phy_kpi_report, phy_outage, recovery_event, recovery_start, sensing_degraded, sensing_failure, sensing_report, sensing_success, signal_degraded, signal_report, target_detected;

// === A_CH: Channel classifier ===
// === A_SIG: Signal classifier ===
// === A_BM: Beam management ===
// === A_SQ: Sensing QoS classifier ===
// === A_PH: Aggregate PHY state ===
// === ENV_*: Closed-system environment stimulus loops ===
// === Obs*: Bounded response observers ===

typedef int[0,3] SINRClassT;
const int SINRCLASS_OUTAGE = 0;
const int SINRCLASS_LOW = 1;
const int SINRCLASS_OK = 2;
const int SINRCLASS_HIGH = 3;
SINRClassT SINRClass = SINRCLASS_OK;

typedef int[0,2] BLERClassT;
const int BLERCLASS_OK = 0;
const int BLERCLASS_HIGH = 1;
const int BLERCLASS_CRITICAL = 2;
BLERClassT BLERClass = BLERCLASS_OK;

typedef int[0,2] CQIClassT;
const int CQICLASS_GOOD = 0;
const int CQICLASS_LIMITED = 1;
const int CQICLASS_BAD = 2;
CQIClassT CQIClass = CQICLASS_GOOD;

typedef int[0,2] IClassT;
const int ICLASS_OK = 0;
const int ICLASS_HIGH = 1;
const int ICLASS_CRITICAL = 2;
IClassT IClass = ICLASS_OK;

typedef int[0,1] DopplerClassT;
const int DOPPLERCLASS_OK = 0;
const int DOPPLERCLASS_HIGH = 1;
DopplerClassT DopplerClass = DOPPLERCLASS_OK;

typedef int[0,1] DelaySpreadClassT;
const int DELAYSPREADCLASS_OK = 0;
const int DELAYSPREADCLASS_HIGH = 1;
DelaySpreadClassT DelaySpreadClass = DELAYSPREADCLASS_OK;

typedef int[0,2] PowerClassT;
const int POWERCLASS_OK = 0;
const int POWERCLASS_LOW = 1;
const int POWERCLASS_ABSENT = 2;
PowerClassT PowerClass = POWERCLASS_OK;

typedef int[0,1] DRTClassT;
const int DRTCLASS_OK = 0;
const int DRTCLASS_BAD = 1;
DRTClassT DRTClass = DRTCLASS_OK;

typedef int[0,2] PilotDensityClassT;
const int PILOTDENSITYCLASS_OK = 0;
const int PILOTDENSITYCLASS_LOW = 1;
const int PILOTDENSITYCLASS_FAILED = 2;
PilotDensityClassT PilotDensityClass = PILOTDENSITYCLASS_OK;

typedef int[0,2] PayloadSenseClassT;
const int PAYLOADSENSECLASS_OK = 0;
const int PAYLOADSENSECLASS_LIMITED = 1;
const int PAYLOADSENSECLASS_FAILED = 2;
PayloadSenseClassT PayloadSenseClass = PAYLOADSENSECLASS_OK;

typedef int[0,2] PRSClassT;
const int PRSCLASS_OK = 0;
const int PRSCLASS_LIMITED = 1;
const int PRSCLASS_FAILED = 2;
PRSClassT PRSClass = PRSCLASS_OK;

typedef int[0,2] BeamErrorClassT;
const int BEAMERRORCLASS_LOCKABLE = 0;
const int BEAMERRORCLASS_UNSTABLE = 1;
const int BEAMERRORCLASS_CRITICAL = 2;
BeamErrorClassT BeamErrorClass = BEAMERRORCLASS_LOCKABLE;

typedef int[0,2] BlockageClassT;
const int BLOCKAGECLASS_NONE = 0;
const int BLOCKAGECLASS_SUSPECTED = 1;
const int BLOCKAGECLASS_CONFIRMED = 2;
BlockageClassT BlockageClass = BLOCKAGECLASS_NONE;

typedef int[0,2] PdClassT;
const int PDCLASS_OK = 0;
const int PDCLASS_LOW = 1;
const int PDCLASS_FAILED = 2;
PdClassT PdClass = PDCLASS_OK;

typedef int[0,2] RfaClassT;
const int RFACLASS_OK = 0;
const int RFACLASS_HIGH = 1;
const int RFACLASS_CRITICAL = 2;
RfaClassT RfaClass = RFACLASS_OK;

typedef int[0,2] AccClassT;
const int ACCCLASS_OK = 0;
const int ACCCLASS_LIMITED = 1;
const int ACCCLASS_FAILED = 2;
AccClassT AccClass = ACCCLASS_OK;

typedef int[0,2] CRBClassT;
const int CRBCLASS_OK = 0;
const int CRBCLASS_LOOSE = 1;
const int CRBCLASS_UNUSABLE = 2;
CRBClassT CRBClass = CRBCLASS_OK;

typedef int[0,2] AoSClassT;
const int AOSCLASS_FRESH = 0;
const int AOSCLASS_STALE = 1;
const int AOSCLASS_EXPIRED = 2;
AoSClassT AoSClass = AOSCLASS_FRESH;

typedef int[0,2] CapClassT;
const int CAPCLASS_OK = 0;
const int CAPCLASS_LIMITED = 1;
const int CAPCLASS_FAILED = 2;
CapClassT CapClass = CAPCLASS_OK;

typedef int[0,2] CoverageClassT;
const int COVERAGECLASS_OK = 0;
const int COVERAGECLASS_LIMITED = 1;
const int COVERAGECLASS_FAILED = 2;
CoverageClassT CoverageClass = COVERAGECLASS_OK;

typedef int[0,2] ResourceShareClassT;
const int RESOURCESHARECLASS_OK = 0;
const int RESOURCESHARECLASS_LIMITED = 1;
const int RESOURCESHARECLASS_STARVED = 2;
ResourceShareClassT ResourceShareClass = RESOURCESHARECLASS_OK;

typedef int[0,2] MisClassT;
const int MISCLASS_OK = 0;
const int MISCLASS_WARN = 1;
const int MISCLASS_CRITICAL = 2;
MisClassT MisClass = MISCLASS_OK;

typedef int[0,2] BMOverheadClassT;
const int BMOVERHEADCLASS_OK = 0;
const int BMOVERHEADCLASS_HIGH = 1;
const int BMOVERHEADCLASS_EXCESSIVE = 2;
BMOverheadClassT BMOverheadClass = BMOVERHEADCLASS_OK;

typedef int[0,5] ChannelClassT;
const int CHANNELCLASS_NOMINAL = 0;
const int CHANNELCLASS_INTERFERENCE_LIMITED = 1;
const int CHANNELCLASS_MOBILITY_LIMITED = 2;
const int CHANNELCLASS_MULTIPATH_LIMITED = 3;
const int CHANNELCLASS_BLOCKAGE = 4;
const int CHANNELCLASS_OUTAGE = 5;
ChannelClassT ChannelClass = CHANNELCLASS_NOMINAL;

typedef int[0,4] SignalClassT;
const int SIGNALCLASS_NOMINAL = 0;
const int SIGNALCLASS_PILOT_BASED = 1;
const int SIGNALCLASS_PAYLOAD_ASSISTED = 2;
const int SIGNALCLASS_RECONFIGURING = 3;
const int SIGNALCLASS_LIMITED = 4;
SignalClassT SignalClass = SIGNALCLASS_NOMINAL;

typedef int[0,7] BeamClassT;
const int BEAMCLASS_SEARCH = 0;
const int BEAMCLASS_TRACK = 1;
const int BEAMCLASS_LOCKED = 2;
const int BEAMCLASS_PREDICT = 3;
const int BEAMCLASS_MISALIGNED = 4;
const int BEAMCLASS_RECOVERING = 5;
const int BEAMCLASS_HO_ASSIST = 6;
const int BEAMCLASS_FAILED = 7;
BeamClassT BeamClass = BEAMCLASS_SEARCH;

typedef int[0,7] SensingStateT;
const int SENSINGSTATE_SENSINGQOSOK = 0;
const int SENSINGSTATE_PROBABILITYLIMITED = 1;
const int SENSINGSTATE_FALSEALARMLIMITED = 2;
const int SENSINGSTATE_ACCURACYLIMITED = 3;
const int SENSINGSTATE_FRESHNESSLIMITED = 4;
const int SENSINGSTATE_COVERAGELIMITED = 5;
const int SENSINGSTATE_CAPACITYLIMITED = 6;
const int SENSINGSTATE_SENSINGFAILURE = 7;
SensingStateT SensingState = SENSINGSTATE_SENSINGQOSOK;

typedef int[0,5] PHYStateT;
const int PHYSTATE_PHYNORMAL = 0;
const int PHYSTATE_PHYCOMMUNICATIONDEGRADED = 1;
const int PHYSTATE_PHYSENSINGDEGRADED = 2;
const int PHYSTATE_PHYJOINTDEGRADED = 3;
const int PHYSTATE_PHYRECOVERY = 4;
const int PHYSTATE_PHYFAILURE = 5;
PHYStateT PHYState = PHYSTATE_PHYNORMAL;

int highest_priority_CH() {
  if (SINRClass == SINRCLASS_OUTAGE) return CHANNELCLASS_OUTAGE;
  if (PowerClass == POWERCLASS_LOW || PowerClass == POWERCLASS_ABSENT) return CHANNELCLASS_BLOCKAGE;
  if (IClass == ICLASS_HIGH || IClass == ICLASS_CRITICAL) return CHANNELCLASS_INTERFERENCE_LIMITED;
  if (DopplerClass == DOPPLERCLASS_HIGH) return CHANNELCLASS_MOBILITY_LIMITED;
  if (DelaySpreadClass == DELAYSPREADCLASS_HIGH) return CHANNELCLASS_MULTIPATH_LIMITED;
  return CHANNELCLASS_NOMINAL;
}

int highest_priority_SQ() {
  if (ChannelClass == CHANNELCLASS_OUTAGE || SignalClass == SIGNALCLASS_LIMITED || BeamClass == BEAMCLASS_FAILED || PdClass == PDCLASS_FAILED || RfaClass == RFACLASS_CRITICAL || AccClass == ACCCLASS_FAILED || CRBClass == CRBCLASS_UNUSABLE || AoSClass == AOSCLASS_EXPIRED || CapClass == CAPCLASS_FAILED || CoverageClass == COVERAGECLASS_FAILED) return SENSINGSTATE_SENSINGFAILURE;
  if (ChannelClass == CHANNELCLASS_BLOCKAGE || SignalClass == SIGNALCLASS_RECONFIGURING || BeamClass == BEAMCLASS_MISALIGNED) return SENSINGSTATE_FRESHNESSLIMITED;
  if (AoSClass == AOSCLASS_STALE) return SENSINGSTATE_FRESHNESSLIMITED;
  if (AccClass == ACCCLASS_LIMITED || CRBClass == CRBCLASS_LOOSE) return SENSINGSTATE_ACCURACYLIMITED;
  if (PdClass == PDCLASS_LOW) return SENSINGSTATE_PROBABILITYLIMITED;
  if (RfaClass == RFACLASS_HIGH) return SENSINGSTATE_FALSEALARMLIMITED;
  if (CapClass == CAPCLASS_LIMITED) return SENSINGSTATE_CAPACITYLIMITED;
  if (CoverageClass == COVERAGECLASS_LIMITED) return SENSINGSTATE_COVERAGELIMITED;
  return SENSINGSTATE_SENSINGQOSOK;
}

bool channel_degraded_flag = false;
bool signal_degraded_flag = false;
bool beam_degraded_flag = false;
bool sensing_degraded_flag = false;
bool sensing_failure_flag = false;
bool degradation_flag = false;
bool child_update = false;
bool input_changed = false;
bool target_seen = false;
bool channel_report_pending = false;
bool signal_report_pending = false;
bool sensing_report_pending = false;
bool phy_kpi_report_pending = false;
bool comm_ok = true;
bool sensing_qos_ok = true;
bool TimingOk = true;
bool ConfigAdmissible = true;
bool BeamCmdAdmissible = true;
bool NetDeliveryOk = true;
bool classes_in_range_ch = true;
bool classes_in_range_sig = true;
bool classes_in_range_bm = true;
bool fresh_child_reports = true;
int[0,1] ch_enabled_count = 1;
int[0,1] sq_enabled_count = 1;

bool ass_ch() { return TimingOk && classes_in_range_ch; }
bool gar_ch() { return classes_in_range_ch; }
bool ass_sig() { return ConfigAdmissible && classes_in_range_sig; }
bool gar_sig() { return classes_in_range_sig; }
bool ass_bm() { return BeamCmdAdmissible && classes_in_range_bm; }
bool gar_bm() { return classes_in_range_bm; }
bool ass_sq() { return fresh_child_reports && gar_ch() && gar_sig() && gar_bm(); }
bool gar_sq() { return true; }
bool ass_ph() { return gar_ch() && gar_sig() && gar_bm() && gar_sq(); }
bool gar_ph() { return true; }
bool ass_env() { return TimingOk && ConfigAdmissible && BeamCmdAdmissible && NetDeliveryOk; }

nta.system:
A_CH = Template_A_CH();
A_SIG = Template_A_SIG();
A_BM = Template_A_BM();
A_SQ = Template_A_SQ();
A_PH = Template_A_PH();
ENV_CH = Template_ENV_CH();
ENV_TARGET = Template_ENV_TARGET();
ENV_MAC = Template_ENV_MAC();
ENV_NET = Template_ENV_NET();
ObsSenseReport = Template_ObsSenseReport();
ObsFreshness = Template_ObsFreshness();
ObsBeamRecovery = Template_ObsBeamRecovery();
system A_CH, A_SIG, A_BM, A_SQ, A_PH, ENV_CH, ENV_TARGET, ENV_MAC, ENV_NET, ObsSenseReport, ObsFreshness, ObsBeamRecovery;
